import sys
input = sys.stdin.readline

def solve():
    n = int(input())
    a = list(map(int, input().split()))
    ops = []

    def rev(p):  # p is length (1-indexed, odd)
        ops.append(p)
        a[:p] = a[:p][::-1]

    end = n - 1  # 0-indexed, even
    while end >= 2:
        # Place a[end+1] (value end+1) at position end
        val = end + 1
        pos = a.index(val)
        if pos != end:
            if pos != 0:
                if pos % 2 == 0:
                    rev(pos + 1)
                else:
                    rev(pos + 2)
                    rev(pos + 1)
            # now val is at a[0], reverse prefix of length end+1
            rev(end + 1)
        # Place value end at position end-1
        val2 = end
        pos2 = a.index(val2)
        if pos2 != end - 1:
            if pos2 != 0:
                if pos2 % 2 == 0:
                    rev(pos2 + 1)
                else:
                    rev(pos2)
            rev(end)  # end is even, so end is odd length? end=n-1 even, end as length... need odd
            # Hmm, end-1+1 = end which is even. Bad.
        end -= 2

    if a == sorted(a):
        print(len(ops))
        print(*ops)
    else:
        print(-1)

t = int(input())
for _ in range(t):
    solve()

